<div class="p-6 space-y-5"><h1 class="text-2xl font-bold">Roles & Permissions</h1><form wire:submit="createRole" class="flex gap-3 rounded-xl border bg-white p-4"><input wire:model="roleName" class="rounded border p-2" placeholder="Role name"><button class="rounded bg-slate-900 px-4 py-2 text-white">Create Role</button></form><div class="grid gap-4"><?php if(\Livewire\Mechanisms\ExtendBlade\ExtendBlade::isRenderingLivewireComponent()): ?><!--[if BLOCK]><![endif]--><?php endif; ?><?php $__currentLoopData = $roles; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $role): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><div class="rounded-xl border bg-white p-4"><div class="flex justify-between"><b><?php echo e($role->name); ?></b><button wire:click="sync(<?php echo e($role->id); ?>)" class="rounded bg-slate-900 px-3 text-white">Save Permissions</button></div><div class="mt-3 grid gap-2 md:grid-cols-4"><?php if(\Livewire\Mechanisms\ExtendBlade\ExtendBlade::isRenderingLivewireComponent()): ?><!--[if BLOCK]><![endif]--><?php endif; ?><?php $__currentLoopData = $allPermissions; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $permission): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><label class="text-sm"><input type="checkbox" wire:model="permissions.<?php echo e($role->id); ?>" value="<?php echo e($permission->name); ?>"> <?php echo e($permission->name); ?></label><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?><?php if(\Livewire\Mechanisms\ExtendBlade\ExtendBlade::isRenderingLivewireComponent()): ?><!--[if ENDBLOCK]><![endif]--><?php endif; ?></div></div><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?><?php if(\Livewire\Mechanisms\ExtendBlade\ExtendBlade::isRenderingLivewireComponent()): ?><!--[if ENDBLOCK]><![endif]--><?php endif; ?></div></div>
